var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"그만!","JPN":"やめて！","ENG":"Enough!","TWN":"住手！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"이제…","JPN":"もう……","ENG":"It's...","TWN":"好了……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":" 그만해, 유피.","JPN":" やめて、ユピ。","ENG":" enough, Yuppie.","TWN":"可以了，悠菲。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"보물찾기는 나중에 해도 되는걸. 나 때문에 친구가 다치는 건 싫어.","JPN":"宝探しはまたやればいい。私のせいで周りの人が傷つくのは見たくない。","ENG":"We can do the treasure hunt later. I don't want my friends to get hurt because of me.","TWN":"尋寶遊戲可以以後再玩。我不想……因為我而讓朋友受傷。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그런 표정으로 말해봤자 설득력 없거든요?","JPN":"そんな顔をしながら訴えても、説得力はないですよ？","ENG":"It's not convincing at all when you say it with that expression on your face.","TWN":"你的表情完全沒有說服力欸？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"유, 유피 일은 내가 어떻게든 해볼게.","JPN":"ゆ、ユピのことは私がなんとかする。","ENG":"I-I'll do everything I can for you.","TWN":"我、我會盡力處理好悠菲的事的。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"난 정말 괜찮아. 그러니까…….","JPN":"私は本当に大丈夫だよ。だから……","ENG":"I'm really fine. So...","TWN":"我真的沒事。所以……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"에휴.","JPN":"はあ……","ENG":"*Sigh*","TWN":"……哀哀。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"끄앙-!","JPN":"きゃふ！？","ENG":"Waah!","TWN":"呃啊——！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_COMIC"},{"id":"L17_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"시그마. 제가 애들한테 제일 듣기 싫어하는 말이 괜찮다는 거예요.","JPN":"シグマ。私が子どもたちから一番聞きたくない言葉は、「大丈夫」です。","ENG":"You know what, Sigma? I hate hearing kids say \\"I'm fine.\\"","TWN":"西格瑪。我最討厭小孩子對我說沒事了。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"한창 제멋대로일 나이에 괜찮은 게 어디 있겠어요? 그건 괜찮은 게 아니라 참는 거예요.","JPN":"いくらでもわがままを言っていい年なのに、大丈夫だなんて、そんなのただ我慢しているだけです。","ENG":"Kids your age are supposed to be stubborn. It's not really \\"fine.\\" You're just holding it in.","TWN":"正是任性妄為的年紀，哪裡會有好孩子？那不是沒事，而是在忍耐。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"하지만… 그럼 착한 아이가 아니게 되는걸.","JPN":"でも……私がいい子でなくなるから。","ENG":"But... I need to be a good girl.","TWN":"但是……那樣的話西格瑪就不是好孩子了。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"어라, 유피. 지금 내 이름 부른 거야?","JPN":"あれ……？　ユピ、今私の名前を呼んでくれた？","ENG":"Wait, Yuppie. Did you just say my name?","TWN":"咦，悠菲。你剛剛是叫我的名字嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"회사 때려친 지가 언젠데 계속 실장님이라 불러요, 그럼?","JPN":"とっくに会社は辞めているのに、いつまでも室長と呼ぶわけにはいきませんからね。","ENG":"I gave up on trying for the company ages ago. I don't need to continue calling you \\"Chief.\\"","TWN":"我都要離開公司了，難道還叫你室長嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"말한 김에 확실히 해두겠는데-","JPN":"はっきり言います。","ENG":"And let me make this clear.","TWN":"話到嘴邊，我就一次說清楚吧。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"본인 목소리를 내느냐가 중요하지. 착하고 나쁘고는 별반 중요하지 않아요.","JPN":"自分の口で意見を言うのが大事なのであって、いい子か悪い子かは重要じゃありません。","ENG":"What's important is whether you speak your mind or not. Being good or bad isn't all that important.","TWN":"重要的是你能否為自己發聲，是否要扮演一個好孩子並不重要。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아이를 올바른 길로 이끌어주는 건 어디까지나 어른의 역할이예요.","JPN":"子どもを正しい方向に導くのは、大人の役目です。","ENG":"It's the adults' responsibility to lead children in the right direction.","TWN":"引導孩子走上正道始終是大人的責任。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"눈치 안 볼 나이에 눈치 보기 시작하면 커서 뭐가 되겠어요?","JPN":"子どもの時から人の顔色をうかがっていては、将来が心配です。","ENG":"What would you become if you were to start pushing things down at an age when you're not supposed to?","TWN":"在不該看人臉色的年紀就唯唯諾諾了，長大後能變成什麼樣子呢？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"유피 양은 저를 참 나쁜 사람으로 만드시는군요.","JPN":"ユピさんはどこまでも私を悪者にしてしまうのですね。","ENG":"You're making me look like the villain here, Yuppie.","TWN":"悠菲真是把我變成一個壞人了呢。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_GOLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"아이 고집이 쇠고집이 된다고. 과잉보호가 매번 정답은 아닙니다.","JPN":"子どもを甘やかしすぎると、言うことを聞かなくなってしまう。そうは思いませんか？","ENG":"You should know that coddling children isn't the answer. They'll grow up to become overtly stubborn adults.","TWN":"孩子的倔脾氣放著不管會越來越倔。過度保護並不是每次都是正確的選擇。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_GOLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"속앓이 하는 것보다는 나아요. 잘못된 게 있다면 알려주고, 책임을 지는 건 저희 몫이니까.","JPN":"我慢ばかりで苦しい思いをするよりは、その方がマシです。間違っていることを正して、その責任を負うのが私たちの役目です。","ENG":"It's better than children suppressing their emotions. It's on us to tell them what's wrong and take responsibility.","TWN":"但總比悶在心裡好受多了。如果有什麼做錯的地方，就告訴我們，因為教育和承擔責任是我們的職責。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"GAP_GOLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"적어도 저만 그렇게 생각한 것도 아니고요.","JPN":"それに、そう思っているのは、私だけではありません。","ENG":"And I'm the only one who thinks that.","TWN":"至少不只是我一個人這麼想。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GAP_GOLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그게 무슨…….","JPN":"それはどういう……","ENG":"What are you–","TWN":"你在做什麼……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GAP_GOLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"야-! 너 거기 안 서?!","JPN":"はあ！？　ちょっと待ちなさい！","ENG":"Hey! Stop right there!","TWN":"喂——！你給我站住？!"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"무얼 숨기랴. 크레데레는 외발 오래 뛰기 기네스 세계기록 보유자입니다.","JPN":"何を隠そう、クレデレはけんけん長距離走の世界記録保持者なのです。","ENG":"No skeletons in this closet. Credere holds the Guinness world record for running on one foot.","TWN":"克蕾妲莉沒有祕密。克蕾妲莉是單腳跳遠的世界紀錄保持者。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L39_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"시그마 해적단원을 얕보지 마시죠, 베이비.","JPN":"シグマ海賊団を甘くみてはいけないぞ、ベイビー。","ENG":"Don't underestimate a crew mate of the Sigma Pirates, baby.","TWN":"別小看西格瑪海盜團的成員，寶貝。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L43_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"휴일에 이게 웬 고생이야. 실전도 이것보다는 덜하겠다!","JPN":"週末になんてことだ。実戦でもこれよりはマシよ！","ENG":"What am I doing on a day off? Even real combat isn't as intense as this!","TWN":"休假還要受這種罪。實戰都沒這麼累過！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"밥맛입니다, 리코리스. 아가씨들 앞에서 폼잡을 땐 언제고 이제 와서 그러시나요.","JPN":"みっともないですよ、リコリス。お嬢さんたちの前であんなにかっこつけておいて、今更何を言っているんですか。","ENG":"That's lame, Lycoris. You say that now, after all that big talk in front of the ladies?","TWN":"真噁心，莉克麗絲。剛才在小姐面前還耍帥，現在又這樣。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"대충 언니들끼리 놀아야 하니 애들은 가라는 내용. 입니다.","JPN":"多分お姉さんたちで遊ぶから、あんたたちは早く行きなさい。と言いましたね。","ENG":"Didn't you say the adults were going to play and that the kids should run along?","TWN":"是誰說接下來是姊姊們的時間，小孩子快點離開的？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그럼 잘못도 없는 애들 앞에서 그래? 원래 애들은 당당해야 한다고!","JPN":"だって、罪のない子どもたちに見せられるわけないじゃない！","ENG":"Then should I have complained in front of the kids? Kids should be shameless and confident!","TWN":"難道要我在孩子面前抱怨啊？小孩子本來就應該理直氣壯的！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"우오오오-! 각성 용병의 총알을 받아라-!!","JPN":"うおおおおっー！　覚醒傭兵の銃弾を喰らえー！！","ENG":"Uaaagh! Witness the true power of Awakened mercenaries!","TWN":"嗚喔喔喔——！覺醒傭兵子彈，接招吧——！！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_RIFLE_FIRE"},{"id":"L50_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하하! 총알 마사지라니 시원하군! 10년은 젊어지는 기분일세!","JPN":"はっはっ！　弾丸マッサージとは効くなぁ！　10歳は若返りそうだ！","ENG":"Ha ha! This bullet massage feels great! I feel 10 years younger!","TWN":"哈哈！子彈按摩真是爽快啊！感覺年輕了十歲！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"이건……?","JPN":"これは……？","ENG":"Those voices are...?","TWN":"這些聲音是……？"},"stage":{"bg":"DEBT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"제가 말했었죠, 시그마. 다른 사람한테 기댈 수 있는 게 어린아이의 특권이라고.","JPN":"言いましたよね、シグマ。他人に頼れるのが、子どもの特権なんだって。","ENG":"I told you, Sigma. Children have the privilege of being able to rely on others.","TWN":"我說過了，西格瑪。依靠別人是孩子的特權。"},"stage":{"bg":"DEBT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"착각한 것 같아서 덧붙이는데… 그게 꼭 민폐라는 소리는 아니에요.","JPN":"何か誤解をしているようなので、補足しておきますが……それは迷惑がかかるという意味で言ったわけではありません。","ENG":"And just to make it clear... that doesn't mean you're a nuisance.","TWN":"我覺得你誤會了……這並不一定是麻煩。"},"stage":{"bg":"DEBT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"결과가 나쁠 순 있겠죠. 괜히 그랬다며 자격지심도 들고, 후회하는 날이 올지도 몰라요.","JPN":"選択の結果によって、よくないことが起きるかもしれません。そして後悔して、自分を責める日が来るかもしれません。","ENG":"Things might not always end well. You might feel regret, or feel like you're not enough.","TWN":"結果可能會不好。也許以後的你會覺得不該那樣做，心生愧疚，甚至會有後悔的一天。"},"stage":{"bg":"DEBT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"하지만 뭐 어때요? 여기 있는 사람들 중 시그마를 나무랄 사람은 아무도 없는데.","JPN":"でも、それはそれでいいんです。ここにいる誰一人、シグマを責めたりなんかしません。","ENG":"But... so what? No one here is going to blame you for it.","TWN":"但那又怎樣呢？這裡沒有人會責怪西格瑪。"},"stage":{"bg":"DEBT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 시그마. 아빠가 없다고 꼭 시그마 혼자서 답을 찾을 필요는 없단다.","JPN":"でもね、パパがいないからといって、必ずシグマ一人で全てを決める必要はないんだよ。","ENG":"But, Sigma. Just because Daddy's not around, that doesn't mean you have to seek answers alone.","TWN":"不過西格瑪。就算爸爸不在，你也不一定非要自己一個人找答案。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"회사에 다른 사람들도 있고… 그래, 해적단의 동료들도 있잖니?","JPN":"会社には社員の人たちもいて……そうだね、海賊団の仲間たちだっているだろう？","ENG":"There are other people in the company, and... you also have your crew mates.","TWN":"公司裡還有其他人……而且，還有海盜團的同伴們不是嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"시그마가 아빠와 모두를 좋아해주는 것처럼.","JPN":"シグマがパパや他のみんなを大好きなのと同じように……","ENG":"Just like how you love me and everyone else,","TWN":"就像西格瑪喜歡爸爸和所有人一樣。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다른 사람들도 분명 시그마를 도와줄 거란다.","JPN":"きっとみんなもシグマを助けたいと思っているはずだ。","ENG":"they're going to want to help you.","TWN":"其他人也一定會樂意幫助西格瑪的。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"괜찮아?","JPN":"いいの？","ENG":"Is that okay?","TWN":"真的可以嗎？"},"stage":{"bg":"DEBT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"난 유피의 가족도 아니고, 계속 민폐만 끼쳤는데.","JPN":"私はユピの家族でもないし、ずっと迷惑ばかりかけてきた。","ENG":"I'm not Yuppie's family member, and I've only been a nuisance so far.","TWN":"西格瑪既不是悠菲的家人，還一直給你添麻煩。"},"stage":{"bg":"DEBT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"민폐라 생각한 적 없어요. 친구잖아요.","JPN":"迷惑だなんて思ったことありません。友達なんですから。","ENG":"I never thought you were a nuisance. We're friends.","TWN":"我從來沒覺得你是麻煩，我們是朋友不是嗎？"},"stage":{"bg":"DEBT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"난 진짜 사람도 아니고… 기계일 뿐인데…….","JPN":"私は人間でもない……ただの機械だよ……","ENG":"But I'm not a real person... I'm just a machine...","TWN":"我甚至不是真正的人……只是個機械而已……"},"stage":{"bg":"DEBT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"선장이 기계인 해적단이라니. 완전 멋지지 않아요?","JPN":"機械の船長がいる海賊団だなんて、かっこいいじゃないですか！","ENG":"A pirate crew with a machine as their captain. Isn't that super cool, though?","TWN":"海盜團的機械海盜船長，想想是不是超酷的？"},"stage":{"bg":"DEBT_03","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DEBT_03","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"동화라고 늘 행복한 결말을 맞이하지는 않아.","JPN":"おとぎ話でさえ、必ずハッピーエンドを迎えるわけじゃない。","ENG":"Fairytales don't always have a happy ending.","TWN":"童話故事並不總是有幸福的結局。"},"stage":{"bg":"EV_SIGMA_08","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"요정의 힘이 영원하지 않듯, 언젠가 꿈에서 깨어나는 날이 올 거야.","JPN":"妖精の力が永遠に続くわけではないように、夢はいつか覚める日がくる。","ENG":"Similar to how the fairy powers won't last forever, there will come a day when I wake up from my dreams.","TWN":"就像精靈的力量也不是永遠的，總有一天會從夢中醒來。"},"stage":{"bg":"EV_SIGMA_08","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"내가 인간이 아니라는 건 알고 있어.","JPN":"私が人間じゃないことなんてわかっている。","ENG":"I know I'm not human.","TWN":"我知道我不是人類。"},"stage":{"bg":"EV_SIGMA_04","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"언젠가 모두와 헤어져야 한다는 것도.","JPN":"いつかみんなと離れる運命なのも。","ENG":"I know that some day I'll have to say goodbye to everyone.","TWN":"總有一天要和大家分離。"},"stage":{"bg":"EV_SIGMA_04","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"그래도 그런 건 신경 쓰이지 않을 만큼 지금이 좋아.","JPN":"でも、そんなの気にならないくらい、私は今が幸せ。","ENG":"But I like the present so much that the future doesn't bother me.","TWN":"不過現在的西格瑪開心到不會在意這些。"},"stage":{"bg":"DEBT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L34_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"지금보다 많은 걸 바라면 요정님도 못 이뤄주는 꿈이 아닐까?","JPN":"これ以上の夢はきっと、妖精さんでも叶えられないよね。","ENG":"Not even the fairy could make the dream come true if I were to wish for something more than I already have.","TWN":"但是如果期望得太多，就算是精靈也無法實現我的夢想吧？"},"stage":{"bg":"DEBT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"걱정 마세요, 시그마. 설령 남들이 보기엔 허황된 꿈일지라도…….","JPN":"大丈夫ですよ、シグマ。たとえ誰かの目には叶わない夢のように映っても……","ENG":"Don't worry, Sigma. Others might think it's a ridiculous dream…","TWN":"別擔心，西格瑪。即使是別人看起來荒謬的夢……"},"stage":{"bg":"DEBT_03","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아직. 해님을 반기기엔 이른 시간이니까.","JPN":"朝日に起こされるのは、まだまだ先です。","ENG":"However, it's too early to be expecting the sunrise.","TWN":"但現在還不是夢醒的時候。"},"stage":{"bg":"DEBT_03","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"침대에서 잔뜩 뒤척이다가 만족스러워질 때 즈음에 꿈에서 깨어나자고요.","JPN":"ベッドの上で好きなだけ眠って、もう十分だと思えたら、そのとき目を覚ましましょう。","ENG":"Let's wake up after we're done rolling around in bed and being as lazy as we want to.","TWN":"在床上翻來覆去，等到滿意的時候再從夢中醒來吧。"},"stage":{"bg":"DEBT_03","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"늦잠 잤다며 아빠한테 혼나더라도, 그땐 제가 같이 혼나줄 테니까.","JPN":"お寝坊さんだとパパに怒られるなら、私も一緒に怒られますから。","ENG":"Even if your dad scolds you for sleeping in, I'll be there to be scolded with you.","TWN":"就算因為睡過頭被爸爸罵，那時候我會陪西格瑪一起挨罵的。"},"stage":{"bg":"DEBT_03","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"말해주세요.","JPN":"言ってください。","ENG":"So, tell me.","TWN":"所以，你自己說，"},"stage":{"bg":"DEBT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"시그마는 어떻게 하고 싶어요?","JPN":"シグマはどうしたいですか？","ENG":"What do you want to do, Sigma?","TWN":"西格瑪你想怎麼做？"},"stage":{"bg":"DEBT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L45_1","type":"narration","speaker":null,"text":{"KOREA":"나는……","JPN":"私は……","ENG":"I...","TWN":"我……"},"stage":{"bg":"DEBT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L46_1","type":"narration","speaker":null,"text":{"KOREA":"내가 하고 싶은 건…….","JPN":"私の望みは……","ENG":"I want to...","TWN":"我想做的是……"},"stage":{"bg":"DEBT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"능동형 출력 제한 모듈 활성화. 현재 평균 출력 2단계 하한 설정 중.","JPN":"能動型出力制限モジュールを活性化。現在平均出力2段階減少設定中。","ENG":"Active output restriction module enabled. Adjusting the current average output by 2 levels.","TWN":"啟動主動輸出限制模組。目前平均輸出已下調為2級。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"해제를 원하시거든 관리자용 코드를 입력하세요.","JPN":"解除をお望みの場合、管理者用のコードを入力してください。","ENG":"Please enter the administrator code to disable.","TWN":"如需解除，請輸入管理者代碼。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>사랑하는 우리 딸</color>. 확인되었습니다. 승인된 음성정보 입력 후 모듈을 비활성화합니다.","JPN":"<color=#ffd34c>大好きな我が娘</color>。確認完了。登録された音声情報が入力された後、モジュールを非活性モードに切り替えます。","ENG":"<color=#ffd34c>My beloved daughter</color>. Confirmed. Disabling the module after entering the approved audio information.","TWN":"<color=#ffd34c>親愛的女兒</color>。已確認。輸入已批准的語音資訊後，模組將被禁用。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_76"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"좀 더 잔뜩, 모두와 놀고 싶어!","JPN":"もっとたくさん、みんなと遊びたい！","ENG":"I want to spend more time playing with everyone!","TWN":"我再繼續想和大家一起玩！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"시그마랑 노는 어느 날, 아빠가 말했네.","JPN":"ある日、私と遊びながらパパは言った。","ENG":"One day, Daddy told me while playing with me.","TWN":"有一天西格瑪和爸爸玩的時候，"},"stage":{"bg":"HAVEN_01","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"자식의 성장이 곧 부모의 행복!","JPN":"子どもの成長こそが親の幸せであると！","ENG":"The growth of a child brings joy to the parent!","TWN":"爸爸說孩子的成長就是父母的幸福！"},"stage":{"bg":"HAVEN_01","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"그래! 아빠 말만 잘 듣는다고 착한 딸이 되는 건 아니었던 거야!","JPN":"そう！　パパの言うことを従順に聞くことだけが、いい娘じゃない！","ENG":"Being a good girl doesn't mean I always have to listen to Daddy!","TWN":"沒錯！光聽爸爸的話並不能成為好女兒！"},"stage":{"bg":"HAVEN_03","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L9_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"좋은 자식은 아빠 말에 수긍하는 게 아닌 수용하는 법이니까!","JPN":"いい子っていうのは、ただ親に従うんじゃなく親から学ぶ子のことだよ！","ENG":"A good girl would accept what Daddy says, not do whatever Daddy says all the time!","TWN":"好孩子應該接受爸爸的話，而不是僅僅照做！"},"stage":{"bg":"HAVEN_01","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L10_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"시그마? 이건?","JPN":"シグマ？　これは……！？","ENG":"Sigma? What's–","TWN":"西格瑪？這是什麼？"},"stage":{"bg":"HAVEN_01","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"용케 여기까지 왔구나, 용사여.","JPN":"よくここまで来たな、勇者よ。","ENG":"So, you have finally come, warrior.","TWN":"你竟然能來到這裡，勇士。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"하지만 거기까진가?","JPN":"しかし、そこまでか？","ENG":"But does the road end here?","TWN":"不過就到此為止嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"보물을 향한 네 집념은, 고작 여기서 무너질 정도였나!","JPN":"貴様のお宝への執念は、その程度だったか！","ENG":"Is your passion for treasure weak enough to crumble here?!","TWN":"你對寶物的執著就只有這樣嗎？！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"에휴. 진작 이랬음 얼마나 좋아.","JPN":"まったく。最初からそう来てほしかったよ。","ENG":"*Sigh* See, was that hard?","TWN":"呼，早這樣不就好了。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그래서, 결국 시그마는 어떻게 하고 싶다는 거예요?","JPN":"結局、シグマはどうしたいんですか？","ENG":"So. What do you want to do, Sigma?","TWN":"所以，西格瑪到底想要怎樣？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"끝내고 싶지 않아.","JPN":"終わらせたくない。","ENG":"I don't want it to end.","TWN":"我還不想結束。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"더 놀고 싶어! 아직 보물찾기는 끝나지 않았는걸!","JPN":"もっと遊びたい！　宝探しはまだ終わってないんだから！","ENG":"I want to play more! The treasure hunt isn't over yet!","TWN":"我還想玩！尋寶遊戲還沒結束呢！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"좋네요-! 그럼 끝장내러 가죠!","JPN":"よーし！　じゃあゲームを終わらせにいきましょう！","ENG":"Goooood! Then, let's go and finish this!","TWN":"很好——！那就上吧！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"응!!","JPN":"うん！！","ENG":"Yay!","TWN":"耶——！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L27_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"제 말을 이해 못 한 건가요?","JPN":"私の言っていることがわかりませんでしたか？","ENG":"Did you not understand what I said?","TWN":"你們沒聽懂我說的話嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_GOLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그 상자는 당신의 아버지가 세상으로부터 직접 격리시킨 물건입니다.","JPN":"その箱はあなたの父親が直接この世から切り離したもの。","ENG":"That chest is something that your father hid from the world.","TWN":"那個箱子是你爸爸親自藏起來的東西。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_GOLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"더는 드러나지 않도록! 철저하게!! 필사적으로!!!","JPN":"二度と世に出てこないように！　徹底的に！！　必死に！！！","ENG":"He hid it thoroughly! Discretely!! Desperately!!!","TWN":"不能曝光！絕對不能！！死也不能！！！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_GOLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"시그마 프로토콜까지 멋대로 사용하다니 제정신인 겁니까?","JPN":"シグマ・プロトコルまで勝手に使うとは、どういうつもりです？","ENG":"What are you thinking, unlocking Sigma Protocol?","TWN":"竟然擅自使用西格瑪協議，你有沒有腦袋？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_GOLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"괜찮아! 아빠가 내가 결정해도 괜찮댔거든!","JPN":"これでいい！　パパは自分で決めてもいいって言ってたもん！","ENG":"It's okay! Daddy told me I could be the one to make decisions!","TWN":"沒關係！爸爸說我自己決定也可以的！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"그치~ 아빠?","JPN":"だよね？　パパ？","ENG":"Right, Daddy?","TWN":"對吧～爸爸？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"우리 딸 하고 싶은 거 다 해!","JPN":"自分の好きなようにやりなさい！","ENG":"Do whatever you want, sweetie!","TWN":"我女兒想做什麼就做什麼！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"우리 딸 하고 싶은 거 다 해!","JPN":"自分の好きなようにやりなさい！","ENG":"Do whatever you want, sweetie!","TWN":"我女兒想做什麼就做什麼！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"우리 딸 하고 싶은 거 다 해!","JPN":"自分の好きなようにやりなさい！","ENG":"Do whatever you want, sweetie!","TWN":"我女兒想做什麼就做什麼！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"당신은 대체 누구 편이야?","JPN":"あなた、いったいどっちの味方なの？","ENG":"Whose side are you on?","TWN":"你到底是哪邊的？！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"너도 마찬가지야! 그런 중요한 결정을 막무가내로…!","JPN":"あんたも同罪よ！　そんな重要な決断を考えもなしに……！","ENG":"And you too! You can't just make that kind of decision willy-nilly–","TWN":"你也一樣！怎麼能這麼魯莽地做出如此重要的決定……！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"막무가내 아니야! 유피도 크레데레도 모두 보물을 찾아 여기까지 왔는걸.","JPN":"そんなことない！　ユピもクレデレも、みんなお宝を見つけるためにここに来たんだから。","ENG":"It's not willy-nilly! Yuppie and Credere all came here in search of treasure.","TWN":"這不是魯莽！悠菲和克蕾妲莉都是為了尋找寶物才來到這裡的。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"선원을 보물로 인도하는 게 선장의 역할이다, 얼!","JPN":"船員をお宝のあるところに導くのが、船長の役目である、ARRR！","ENG":"It's the captain's role to lead her crew to treasure, yarr!","TWN":"引導船員找到寶物是船長的職責，唷呵！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"마왕인지 선장인지는 모르겠지만 말 한 번 잘하셨어요, 시그마.","JPN":"魔王なのか船長なのかよくわかりませんが、その通りです、シグマ。","ENG":"I'm not sure if you're a Demon Lord or a captain, but well said, Sigma.","TWN":"不管你是魔王還是船長，這次你說得沒錯，西格瑪。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"제 빚이 원금액보다 불어나기 전에 슬슬 끝내보자고요.","JPN":"私の借金がより大きく膨らむ前に、一気に片付けましょう。","ENG":"Let's get this over with before my debt grows any bigger.","TWN":"在我的債務還沒變得更多之前，趕緊結束它吧？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"그게 아냐, 유피 선원. 좀 더 해적스럽게 말해야지!","JPN":"違うでしょ、ユピ船員。もっと海賊らしい言葉で言わないと！","ENG":"No no, Yuppie, you have to say it like a true pirate!","TWN":"不對，悠菲船員！要更像海盜一樣說話才行！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"요호호-. 마귀상어를 물리칠 준비가 끝났습니다, 캡.","JPN":"おほほっ、ババアサメを仕留める準備は完璧です、キャプテン。","ENG":"Yo ho ho. I'm ready to defeat the wicked shark, Cap.","TWN":"喔呵呵——準備好擊退魔鬼鯊了，船長。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"요호호-! 마귀상어를 향해 선전포고다, 유피 선원!","JPN":"おほほほっ、ババアサメメに対して宣戦布告だ、ユピ船員！","ENG":"Yo ho ho! Let's declare war against the wicked shark, Yuppie!","TWN":"喔呵呵——！向魔鬼鯊宣戰吧，悠菲船員！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L3_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아아-. 듣고 계십니까, 아줌마.","JPN":"あーあー、聞こえておりますでしょうか、おばさん。","ENG":"Mic test, one, two. Can you hear us, you old Vice President?","TWN":"啊啊，你在聽嗎，大嬸？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"이런, 머리를 너무 세게 맞았나 보군요. 사람 면전에다 대고 저런 헛소리라니.","JPN":"あら、頭を強く打ちすぎたようですね。人様に面と向かってそんなことが言えるとは。","ENG":"Oh, my. Seems like you've suffered a severe head injury to be saying such rude things to me.","TWN":"呵呵，你是不是被打傻了？開始胡言亂語？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"지금까지 먹은 나이는 장식인가용?","JPN":"その歳になるまで、学ばなかったんでちゅか？","ENG":"You're soooo old, and yet you're so faw fwom being wise.","TWN":"看來你是白長這麼大年紀？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"애들 괴롭히면서 히히덕거리는 걸 보니 분명 성격도 나쁜 거에용.","JPN":"子どもをいじめてヘラヘラ笑っているなんて、性格悪いのが丸わかりでちゅよ。","ENG":"You're just a wicked old lady who giggles while tortuwing childwen.","TWN":"欺負小孩還笑得那麼開心，性格肯定也不怎麼樣嘛。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"……지금 뭐 하자는 거죠?","JPN":"……なんですって？","ENG":"...What is the meaning of this?","TWN":"……你做這些到底想幹什麼？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"글쎄요. 저도 잘 모르겠네요. 살다 살다 면접 보러 온 회사 부사장이랑 싸움이라니.","JPN":"そうですね。自分でもよくわかりません。まさか面接を受けにきて、その会社の副社長と喧嘩する日がくるなんて。","ENG":"I'm not sure. I never dreamed that I would fight the Vice President of the company I applied for.","TWN":"這個？我也不太清楚。我長這麼大，還是第一次和面試我的公司副總打架呢。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"기왕 이렇게 된 김에, 애들한테 들려줄 무용담이나 하나 만들어가는 게 좋지 않겠어요?","JPN":"でもこうなったからには仕方ありませんよね。せっかくですし、子どもたちへの土産話くらい用意しておかないと。","ENG":"But here I am. So why not make the most of it and create another tale to tell the children?","TWN":"事已至此，不如編個故事給孩子們聽吧？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"결론은 물론… 애들이 좋아할법한 이야기로.","JPN":"それはもちろん……子どもたちが喜びそうな物語をです。","ENG":"And the ending is going to be... something that the kids will enjoy.","TWN":"當然是結局……會讓孩子們喜歡的故事。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그 귀에 때려 박아 놓으세요. 지금부터 이기는 건-.","JPN":"よく聞いてください。今から勝つのは―","ENG":"So, I'm telling you loud and clear. The winning team is–","TWN":"把我的話聽清楚了。從現在開始，勝利是——"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"보물을 차지하는 건-!","JPN":"お宝を手に入れるのは―！","ENG":"The treasure belongs to–","TWN":"寶藏是——!"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"시그마 해적단의 몫이다!!","JPN":"シグマ海賊団だ！！","ENG":"The Sigma Pirates!","TWN":"屬於西格瑪海盜團的！！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};